import { PixelArtImageModel } from './pixelart-image-model';
import type { PixelArtImageModelId } from './pixelart-image-settings';
import { VERSION } from './version';

// ---------------------------------------------------------------------------
// Provider settings (user-facing)
// ---------------------------------------------------------------------------

export interface PixelArtProviderSettings {
  /**
   * PixelArt API key.
   * Defaults to the value of the `PIXELART_API_KEY` environment variable.
   */
  apiKey?: string;

  /**
   * Base URL for the PixelArt API.
   * Defaults to `https://api.pixelart.ai/v1`.
   */
  baseURL?: string;

  /**
   * Additional HTTP headers to include in every request.
   */
  headers?: Record<string, string>;

  /**
   * Custom `fetch` implementation.
   * Useful as middleware (e.g. logging, retries) or for testing.
   */
  fetch?: FetchFunction;
}

// ---------------------------------------------------------------------------
// Provider interface
// ---------------------------------------------------------------------------

export interface PixelArtProvider {
  /**
   * Provider specification version — always `'v3'`.
   */
  readonly specificationVersion: 'v3';

  /**
   * Creates an image generation model.
   *
   * @param modelId - The PixelArt model to use (e.g. `"pixelart-v1"`).
   */
  image(modelId: PixelArtImageModelId): ImageModelV3;

  /**
   * Creates an image generation model.
   * Alias for `image()`.
   *
   * @param modelId - The PixelArt model to use (e.g. `"pixelart-v1"`).
   */
  imageModel(modelId: PixelArtImageModelId): ImageModelV3;
}

// ---------------------------------------------------------------------------
// Factory
// ---------------------------------------------------------------------------

const defaultBaseURL = 'https://api.pixelart.ai/v1';

