 * Creates a configured PixelArt provider instance.
 *
 * @example
 * ```ts
 * import { createPixelArt } from '@ai-sdk/pixelart';
 * import { generateImage } from 'ai';
 *
 * const pixelArt = createPixelArt({ apiKey: process.env.PIXELART_API_KEY });
 *
 * const { image } = await generateImage({
 *   model: pixelArt.image('pixelart-v1'),
 *   prompt: 'A medieval castle at sunset',
 *   providerOptions: {
 *     pixelart: { style: '8bit', pixelDensity: 72 },
 *   },
 * });
 * ```
 */
export function createPixelArt(
  options: PixelArtProviderSettings = {},
): PixelArtProvider {
  const baseURL =
    withoutTrailingSlash(options.baseURL ?? defaultBaseURL) ?? defaultBaseURL;

  const getHeaders = () =>
    withUserAgentSuffix(
      {
        Authorization: `Bearer ${loadApiKey({
          apiKey: options.apiKey,
          environmentVariableName: 'PIXELART_API_KEY',
          description: 'PixelArt',
        })}`,
        ...options.headers,
      },
      `ai-sdk/pixelart/${VERSION}`,
    );

  const createImageModel = (modelId: PixelArtImageModelId): ImageModelV3 =>
    new PixelArtImageModel(modelId, {
      provider: 'pixelart.image',
      baseURL,
      headers: getHeaders,
      fetch: options.fetch,
    });

  return {
    specificationVersion: 'v3',
    image: createImageModel,
    imageModel: createImageModel,

    // PixelArt is image-only — throw descriptive errors for other model types
    // so users get a clear message instead of a cryptic runtime failure.
    languageModel: (modelId: string) => {
      throw new NoSuchModelError({ modelId, modelType: 'languageModel' });
    },
    embeddingModel: (modelId: string) => {
      throw new NoSuchModelError({ modelId, modelType: 'embeddingModel' });
    },
  } as PixelArtProvider & {
    languageModel: (modelId: string) => never;
    embeddingModel: (modelId: string) => never;
  };
}

/**
 * Default PixelArt provider instance.
 * Uses the `PIXELART_API_KEY` environment variable for authentication.
 */
export const pixelArt = createPixelArt();

