import type { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import type { InferSchema, Resolvable } from '@ai-sdk/provider-utils';
import {
  type FetchFunction,
  combineHeaders,
  createJsonErrorResponseHandler,
  createJsonResponseHandler,
  lazySchema,
  parseProviderOptions,
  postJsonToApi,
  resolve,
  zodSchema,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';
import type { PixelArtImageModelId } from './pixelart-image-settings';

// ---------------------------------------------------------------------------
// Config (internal, not exported)
// ---------------------------------------------------------------------------

interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers?: Resolvable<Record<string, string | undefined>>;
  fetch?: FetchFunction;
}

// ---------------------------------------------------------------------------
// Model class
// ---------------------------------------------------------------------------

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';

  /**
   * PixelArt's synchronous API produces one image per call.
   * The AI SDK will automatically parallelise requests when `n > 1`.
   */
  readonly maxImagesPerCall = 1;

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate({
    prompt,
    n,
    size,
    aspectRatio,
    seed,
    files,
    mask,
    providerOptions,
    headers,
    abortSignal,
  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<
    Awaited<ReturnType<ImageModelV3['doGenerate']>>
  > {
    const warnings: Array<SharedV3Warning> = [];

    // Warn about unsupported standard options
    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
        details:
          'PixelArt does not support aspectRatio. Use the size parameter to specify dimensions.',
      });
    }

    if (files != null && files.length > 0) {
      warnings.push({
        type: 'unsupported',
        feature: 'files',
        details: 'PixelArt does not support image-to-image generation.',
      });
    }

    if (mask != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'mask',
        details: 'PixelArt does not support inpainting with masks.',
      });
    }

    // Parse provider-specific options (style, pixelDensity)
    const pixelArtOptions = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions,
      schema: pixelArtImageModelOptionsSchema,
    });

    const body: Record<string, unknown> = {
      model: this.modelId,
      prompt,
      n,
      size,
      seed,
      style: pixelArtOptions?.style,
      pixel_density: pixelArtOptions?.pixelDensity,
    };

    const { value, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/generate`,
      headers: combineHeaders(await resolve(this.config.headers), headers),
      body,
      failedResponseHandler: pixelArtFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(
        pixelArtResponseSchema,
      ),
      abortSignal,
      fetch: this.config.fetch,
    });

    return {
      images: value.images.map(img => img.b64_json),
      warnings,
      response: {
        timestamp: new Date(),
        modelId: this.modelId,
        headers: responseHeaders,
      },
    };
  }
}

// ---------------------------------------------------------------------------
// Provider-specific options schema
// ---------------------------------------------------------------------------

export const pixelArtImageModelOptionsSchema = lazySchema(() =>
  zodSchema(
    z.object({
      /**
       * Rendering style for the generated image.
       */
      style: z.enum(['pixel', 'retro', '8bit']).optional(),

      /**
       * Pixel density of the output (analogous to DPI).
       * Must be a positive number.
       */
      pixelDensity: z.number().positive().optional(),
    }),
  ),
);

export type PixelArtImageModelOptions = InferSchema<
  typeof pixelArtImageModelOptionsSchema
>;

// ---------------------------------------------------------------------------
// Response / error schemas
// ---------------------------------------------------------------------------

const pixelArtResponseSchema = z.object({
  images: z.array(
    z.object({
      b64_json: z.string(),
    }),
  ),
});

const pixelArtErrorSchema = z.object({
  error: z
    .object({
      message: z.string().optional(),
      code: z.string().optional(),
    })
    .optional(),
  message: z.string().optional(),
});

const pixelArtFailedResponseHandler = createJsonErrorResponseHandler({
  errorSchema: pixelArtErrorSchema,
  errorToMessage: error =>
    error.error?.message ?? error.message ?? 'Unknown PixelArt error',
});
